class Solution:
    def countSteppingNumbers(self, low: str, high: str) -> int:
        MOD = 10**9 + 7

        def count_stepping_numbers_less_equal(s: str) -> int:
            n = len(s)
            dp = [[[[ -1 for _ in range(2)] for __ in range(10)] for ___ in range(2)] for ____ in range(n)]

            def dp_func(pos: int, prev_digit: int, tight: int, leading_zero: int) -> int:
                if pos == n:
                    return 0 if leading_zero else 1
                if dp[pos][prev_digit][tight][leading_zero] != -1:
                    return dp[pos][prev_digit][tight][leading_zero]

                limit = int(s[pos]) if tight else 9
                total = 0

                for d in range(0, limit + 1):
                    new_tight = tight and (d == limit)
                    new_leading_zero = leading_zero and (d == 0)
                    new_prev_digit = d if not new_leading_zero else prev_digit

                    if not new_leading_zero and abs(new_prev_digit - d) != 1:
                        continue

                    total += dp_func(pos + 1, d, new_tight, new_leading_zero)
                    total %= MOD

                dp[pos][prev_digit][tight][leading_zero] = total
                return total

            return dp_func(0, 0, 1, 1)

        count_high = count_stepping_numbers_less_equal(high)
        count_low_minus_1 = count_stepping_numbers_less_equal(str(int(low) - 1))

        return (count_high - count_low_minus_1) % MOD
